1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
7	const THREE_ALIKE_BLOCK_PREMIUM = 60;
8	
9	type ItemTypeSpec = { basePremium: number; isComponent: boolean };
10	
11	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
12	  sword: { basePremium: 100, isComponent: false },
13	  amulet: { basePremium: 60, isComponent: false },
14	  rune: { basePremium: 25, isComponent: true },
15	  moonstone: { basePremium: 25, isComponent: true },
16	};
17	
18	const specFor = (type: string): ItemTypeSpec => ITEM_TYPES[type];
19	
20	const groupByType = (items: Item[]): Map<string, Item[]> =>
21	  items.reduce((groups, item) => {
22	    const group = groups.get(item.type) ?? [];
23	    return groups.set(item.type, [...group, item]);
24	  }, new Map<string, Item[]>());
25	
26	const basePremiumForGroup = (group: Item[]): number => {
27	  const spec = specFor(group[0].type);
28	  if (spec.isComponent && group.length === 3) return THREE_ALIKE_BLOCK_PREMIUM;
29	  return group.length * spec.basePremium;
30	};
31	
32	const basePremiumFor = (items: Item[]): number =>
33	  [...groupByType(items).values()]
34	    .reduce((sum, group) => sum + basePremiumForGroup(group), 0);
35	
36	const applyFirstInsuranceSurcharge = (premium: number): number =>
37	  premium + (premium * FIRST_INSURANCE_SURCHARGE_PERCENT) / 100;
38	
39	const quotePremium = (items: Item[]): number =>
40	  Math.ceil(applyFirstInsuranceSurcharge(basePremiumFor(items))) + PROCESSING_FEE;
41	
42	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
43	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
44	  return { results };
45	};
