const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const basePremiumForGroup = (type: string, count: number): number => {
  const spec = specFor(type);
  if (spec.isComponent && count === 3) return THREE_ALIKE_BLOCK_PREMIUM;
  return count * spec.basePremium;
};

const basePremiumFor = (items: Item[]): number =>
  [...countByType(items)]
    .reduce((sum, [type, count]) => sum + basePremiumForGroup(type, count), 0);
